// 最小化的 JavaScript 实现以获得最佳性能
(function () {
  "use strict";

  // DOM 元素
  const claimBtn = document.getElementById("claimBtn");
  const closeBtn = document.getElementById("closeBtn");
  const handDecoration = document.getElementById("handDecoration");
  const modalOverlay = document.getElementById("modalOverlay");
  const paypalSuccess = document.getElementById("paypalSuccess");

  // URL 参数处理（提前到函数开始）
  const urlParams = new URLSearchParams(window.location.search);
  const channel = urlParams.get("chl");

  // 设置渠道
  if (channel && typeof window.setOriginalChannel === "function") {
    window.setOriginalChannel(channel);
  }

  // 埋点：落地页显示
  if (typeof window.bytePlusTrack === "function") {
    window.bytePlusTrack("pwa_conv_lp_show");
    // 广告埋点：落地页显示
    window.bytePlusTrack("ad_pwa_conv_lp_show");

    // 广告落地页埋点
    const isChrome = window.chrome && /Chrome/.test(navigator.userAgent);
    if (isChrome) {
      window.bytePlusTrack("web_ads_link_page_show");
    } else {
      window.bytePlusTrack("web_ads_link_page_show_non_chrome");
    }
  }

  // 打开 Chrome 浏览器（Android Intent）
  function openInChrome(path, params) {
    let paramStr = "";
    if (params) {
      paramStr = Object.keys(params)
        .filter((key) => params[key] != null)
        .map((key) => `${key}=${params[key]}`)
        .join("&");
      paramStr = `?${paramStr}`;
    }

    const intentUrl = `intent://${window.location.host}/${path}${paramStr}#Intent;scheme=https;package=com.android.chrome;end`;
    window.location.href = intentUrl;
  }

  // 处理领取按钮点击
  function handleClaim() {
    // 埋点：落地页按钮点击
    if (typeof window.bytePlusTrack === "function") {
      window.bytePlusTrack("pwa_conv_lp_clickButton");
      // 广告埋点：落地页按钮点击
      window.bytePlusTrack("ad_pwa_conv_lp_clickButton");

      // 广告提现点击埋点
      var isChromeBrowser = window.chrome && /Chrome/.test(navigator.userAgent);
      if (isChromeBrowser) {
        window.bytePlusTrack("pwa_ad_cashout_click");
      } else {
        window.bytePlusTrack("pwa_ad_cashout_click_non_chrome");
      }
    }
    if (typeof window.adTrack === "function") {
      window.adTrack("ClickButton");
    }

    // 判断浏览器类型
    const isChrome = window.chrome && /Chrome/.test(navigator.userAgent);

    if (isChrome) {
      // Chrome 用户：跳转到等待页面
      window.location.href = "/activity/installToClaim.html" + window.location.search;
    } else {
      // 非 Chrome 用户：显示 PayPal 成功页并打开 Chrome
      modalOverlay.classList.add("hidden");
      paypalSuccess.classList.remove("hidden");

      // 收集所有 URL 参数
      const allParams = {};
      urlParams.forEach((value, key) => {
        allParams[key] = value;
      });

      if (channel) {
        allParams.chl_trans = channel;
      }

      // 打开 Chrome 浏览器
      openInChrome("activity/installToClaim.html", allParams);
    }
  }

  // 事件监听器
  if (claimBtn) claimBtn.addEventListener("click", handleClaim);
  if (closeBtn) closeBtn.addEventListener("click", handleClaim);
  if (handDecoration) handDecoration.addEventListener("click", handleClaim);

  // 防止触摸设备上的滚动
  document.body.addEventListener(
    "touchmove",
    function (e) {
      e.preventDefault();
    },
    { passive: false },
  );

  // 预加载下一页
  const installUrl = "/activity/install-to-claim.html" + window.location.search;
  const link = document.createElement("link");
  link.rel = "prefetch";
  link.href = installUrl;
  document.head.appendChild(link);
})();
